INSERT INTO `herb` (`id`, `name`, `pinyin`, `aliases`, `source`, `medicinal_part`, `nature`, `taste`, `meridian`, `effects`, `indications`, `usage`, `processing`, `origin`, `toxicity`, `category`, `create_time`, `update_time`) VALUES
(1, '人参', 'ren shen', '神草、棒锤、山参', '五加科植物人参 Panax ginseng C.A.Mey.的干燥根和根茎', '根及根茎', '微温', '甘、微苦', '脾、肺、心、肾经', '大补元气，复脉固脱，补脾益肺，生津养血，安神益智', '用于气虚欲脱，脉微欲绝，脾虚食少，肺虚喘咳，津伤口渴，内热消渴，气血亏虚，失眠健忘', '3-9g，另炖兑服', '洗净切片或生用、炒用', '吉林、辽宁、黑龙江', 'NONE', '补气药', NOW(), NOW()),
(2, '甘草', 'gan cao', '甜草、国老、蜜草', '豆科植物甘草 Glycyrrhiza uralensis Fisch.、胀果甘草或光果甘草的干燥根和根茎', '根及根茎', '平', '甘', '心、肺、脾、胃经', '补脾益气，清热解毒，祛痰止咳，缓急止痛，调和诸药', '用于脾胃虚弱，倦怠乏力，心动悸，脉结代，咳嗽痰多，脘腹挛急疼痛，调和诸药', '2-10g', '生用或蜜炙用', '内蒙古、甘肃、新疆', 'NONE', '补气药', NOW(), NOW()),
(3, '黄连', 'huang lian', '连桥、王连、雅连', '毛茛科植物黄连、三角叶黄连或云连的干燥根茎', '根茎', '寒', '苦', '心、脾、胃、肝、胆、大肠经', '清热燥湿，泻火解毒', '用于湿热痞满，呕吐吞酸，高热神昏，心火亢盛，心烦不寐，血热吐衄，目赤吞酸，牙痛，痈肿疔疮', '2-5g', '姜汁炒或吴茱萸水炒', '四川、云南、陕西', 'NONE', '清热药', NOW(), NOW()),
(4, '当归', 'dang gui', '干归、马尾当归、秦归', '伞形科植物当归 Angelica sinensis (Oliv.) Diels 的干燥根', '根', '温', '甘、辛', '肝、心、脾经', '补血活血，调经止痛，润肠通便', '用于血虚萎黄，眩晕心悸，月经不调，经闭痛经，虚寒腹痛，风湿痹痛，跌扑损伤，肠燥便秘', '6-12g', '生用或酒炒、土炒', '甘肃、云南、四川', 'NONE', '补血药', NOW(), NOW()),
(5, '丹参', 'dan shen', '红丹参、赤参、紫丹参', '唇形科植物丹参 Salvia miltiorrhiza Bge.的干燥根和根茎', '根及根茎', '微寒', '苦', '心、肝经', '活血祛瘀，通经止痛，清心除烦，凉血消痈', '用于胸痹心痛，脘腹胁痛，瘕瘕积聚，热病烦躁神昏，心烦不眠，瘀滞腹痛，跌打损伤，疮疡肿痛', '9-15g', '生用或酒炙', '四川、河北、山东', 'NONE', '活血化瘀药', NOW(), NOW()),
(6, '黄芪', 'huang qi', '绵黄芪、金黄芪', '豆科植物蒙古黄芪或膜荚黄芪的干燥根', '根', '微温', '甘', '脾、肺经', '补气升阳，固表止汗，利水消肿，生津养血，托毒排脓', '用于气虚乏力，食少便溏，中气下陷，表虚自汗，气虚水肿，血虚萎黄，痈疽难溃', '9-30g', '生用或蜜炙', '内蒙古、山西、甘肃', 'NONE', '补气药', NOW(), NOW()),
(7, '白芍', 'bai shao', '金芍、毛芍', '毛茛科植物芍药 Paeonia lactiflora Pall.的干燥根', '根', '微寒', '苦、酸', '肝、脾经', '养血调经，敛阴止汗，柔肝止痛，平抑肝阳', '用于血虚萎黄，月经不调，自汗盗汗，胁痛，腹痛，四肢挛痛，肝阳上亢', '6-15g', '生用或炒用、酒炒', '浙江、安徽、四川', 'NONE', '补血药', NOW(), NOW()),
(8, '川芎', 'chuan xiong', '抚芎、香果、胡芎', '伞形科植物川芎 Ligusticum chuanxiong Hort.的干燥根茎', '根茎', '温', '辛', '肝、胆、心包经', '活血行气，祛风止痛', '用于胸痹心痛，胁痛，痛经经闭，瘕瘕腹痛，头痛，风湿痹痛', '3-10g', '生用', '四川', 'NONE', '活血化瘀药', NOW(), NOW()),
(9, '茯苓', 'fu ling', '茯灵、云苓、茯神', '多孔菌科真菌茯苓 Poria cocos (Schw.) Wolf 的干燥菌核', '菌核', '平', '甘、淡', '心、脾、肾经', '利水渗湿，健脾，宁心', '用于水肿尿少，痰饮眩悸，脾虚食少，便溏泄泻，心神不安，失眠健忘', '10-15g', '生用', '云南、安徽、湖北', 'NONE', '利水渗湿药', NOW(), NOW()),
(10, '半夏', 'ban xia', '蝎子草、地文', '天南星科植物半夏 Pinellia ternata (Thunb.) Breit.的干燥块茎', '块茎', '温', '辛', '脾、胃、肺经', '燥湿化痰，降逆止呕，消痞散结', '用于湿痰寒痰，咳喘痰多，痰饮眩悸，呕吐，心下痞，结胸，梅核气', '3-9g，需炮制后使用', '姜半夏、法半夏、清半夏', '四川、湖北、安徽', 'LOW', '化痰药', NOW(), NOW());
