(1, '四君子汤', '无', '《太平惠民和剂局方》', '宋代', '补益剂', '益气健脾', '脾胃气虚证，面色萎白，语声低微，气短乏力，食少便溏', '水煎服，日一剂', '[{"name":"人参","dose":"9g"}]', '[{"name":"白术","dose":"9g"},{"name":"茯苓","dose":"9g"}]', '[{"name":"甘草","dose":"6g"}]', '无', '["人参","白术","茯苓","甘草"]', 8.5, NOW(), NOW()),
