(3, '桂枝汤', '无', '《伤寒论》', '东汉', '解表剂', '解肌发表，调和营卫', '外感风寒表虚证，发热头痛，汗出恶风，鼻鸣干呕', '水煎温服，服后啜热稀粥助汗', '[{"name":"桂枝","dose":"9g"}]', '[{"name":"芍药","dose":"9g"}]', '[{"name":"生姜","dose":"9g"},{"name":"大枣","dose":"4 枚"}]', '[{"name":"甘草","dose":"6g"}]', '["桂枝","芍药","生姜","大枣","甘草"]', 8.0, NOW(), NOW()),
(4, '麻黄汤', '无', '《伤寒论》', '东汉', '解表剂', '发汗解表，宣肺平喘', '外感风寒表实证，恶寒发热，头痛身痛，无汗而喘', '水煎服，日一剂', '[{"name":"麻黄","dose":"9g"}]', '[{"name":"桂枝","dose":"6g"}]', '[{"name":"杏仁","dose":"9g"}]', '[{"name":"甘草","dose":"3g"}]', '["麻黄","桂枝","杏仁","甘草"]', 7.8, NOW(), NOW()),
(5, '小柴胡汤', '无', '《伤寒论》', '东汉', '和解剂', '和解少阳，扶正祛邪', '少阳证，寒热往来，胸胁苦满，默默不欲饮食，心烦喜呕', '水煎服，日一剂', '[{"name":"柴胡","dose":"12g"}]', '[{"name":"黄芩","dose":"9g"}]', '[{"name":"半夏","dose":"9g"},{"name":"生姜","dose":"9g"}]', '[{"name":"人参","dose":"6g"},{"name":"甘草","dose":"6g"},{"name":"大枣","dose":"4 枚"}]', '["柴胡","黄芩","半夏","人参","甘草","生姜","大枣"]', 9.0, NOW(), NOW()),
(6, '六味地黄丸', '地黄丸', '《小儿药证直诀》', '宋代', '补益剂', '滋阴补肾', '肾阴亏损证，头晕耳鸣，腰膝酸软，骨蒸潮热，盗汗遗精', '水蜜丸，一次 6-9g，一日 2 次', '[{"name":"熟地黄","dose":"24g"}]', '[{"name":"山茱萸","dose":"12g"},{"name":"山药","dose":"12g"}]', '[{"name":"泽泻","dose":"9g"},{"name":"牡丹皮","dose":"9g"},{"name":"茯苓","dose":"9g"}]', '无', '["熟地黄","山茱萸","山药","泽泻","牡丹皮","茯苓"]', 9.2, NOW(), NOW());
