(1, '2 型糖尿病', '消渴病', '内科', 'MODERATE', '以血浆葡萄糖水平升高为特征的代谢性疾病', '多饮、多食、多尿、体重减轻，口渴喜饮，小便频数', '[{"name":"肺热津伤"},{"name":"胃热炽盛"},{"name":"肾阴亏虚"}]', '["消渴方","玉液汤","六味地黄丸"]', '["天花粉","葛根","山药","黄芪","地黄"]', NOW(), NOW()),
(2, '高血压', '眩晕、头痛', '内科', 'MODERATE', '以体循环动脉血压持续升高为主要特征的临床综合征', '头晕、头痛、耳鸣、心悸、失眠，严重者可致心脑肾并发症', '[{"name":"肝阳上亢"},{"name":"痰湿中阻"},{"name":"肝肾阴虚"}]', '["天麻钩藤饮","半夏白术天麻汤","杞菊地黄丸"]', '["天麻","钩藤","石决明","半夏","白术"]', NOW(), NOW()),
