(6, '阿尔茨海默病', '痴呆', '神经内科', 'SEVERE', '一种以进行性认知功能下降为特征的神经退行性疾病', '记忆力下降，执行功能减退，定向力障碍，行为情绪改变', '[{"name":"髓海不足"},{"name":"痰瘀阻窍"},{"name":"肝肾亏虚"}]', '["洗心汤","补阳还五汤","归脾汤"]', '["石菖蒲","远志","丹参","黄芪","人参"]', NOW(), NOW()),
(7, '非酒精性脂肪性肝病', '胁痛、积聚', '消化内科', 'MODERATE', '与胰岛素抵抗和代谢综合征密切相关的慢性肝病', '乏力，右上腹不适，肝功能异常，影像学提示脂肪肝', '[{"name":"湿热内蕴"},{"name":"痰瘀互结"},{"name":"肝郁脾虚"}]', '["茵陈蒿汤","柴胡疏肝散","丹栀逍遥散"]', '["茵陈","泽泻","丹参","柴胡","黄芩"]', NOW(), NOW()),
(8, '慢性肾脏病', '水肿、腰痛', '肾内科', 'SEVERE', '各种病因引起的慢性肾结构和功能异常', '浮肿，乏力，夜尿增多，蛋白尿，血肌酐升高', '[{"name":"脾肾阳虚"},{"name":"肝肾阴虚"},{"name":"湿浊瘀阻"}]', '["真武汤","六味地黄丸","济生肾气丸"]', '["黄芪","茯苓","泽泻","山茱萸","丹参"]', NOW(), NOW()),
(9, '抑郁障碍', '郁证', '精神心理', 'MODERATE', '以显著而持久的情绪低落为核心症状的精神障碍', '情绪低落，兴趣减退，睡眠障碍，乏力，食欲改变', '[{"name":"肝气郁结"},{"name":"心脾两虚"},{"name":"痰气郁结"}]', '["柴胡疏肝散","逍遥散","甘麦大枣汤"]', '["柴胡","白芍","香附","郁金","合欢皮"]', NOW(), NOW()),
(10, '骨关节炎', '痹证', '骨科', 'MODERATE', '以关节软骨退行性变和继发骨质增生为特点的慢性关节病', '关节疼痛僵硬，活动受限，晨僵，劳累后加重', '[{"name":"风寒湿痹"},{"name":"肝肾不足"},{"name":"瘀血阻络"}]', '["独活寄生汤","身痛逐瘀汤","补肾壮骨方"]', '["独活","杜仲","牛膝","当归","川芎"]', NOW(), NOW());
